            res = mul(a, b)
        elif op == "div":
            res = div(a, b)
        else:
            raise ValueError(f"Unknown operation: {op}")

        self.history.append({
            "expression": f"{a} {op} {b}",
            "result": res,
            "timestamp": datetime.datetime.now().isoformat()
        })
        save_history(self.history)
        return res

    def get_history(self) -> list[dict]:
        return self.history

    def clear_history(self) -> None:
        self.history = []
        save_history(self.history)
